"""matplotlib.container — container classes for grouped artists."""


class Container(tuple):
    def __new__(cls, kl, label=None):
        return tuple.__new__(cls, kl)

    def __init__(self, kl, label=None):
        self._label = label or ''

    def get_label(self): return self._label
    def set_label(self, s): self._label = s
    def get_children(self): return list(self)
    def remove(self): pass


class BarContainer(Container):
    def __init__(self, patches, errorbar=None, *, datavalues=None, orientation=None, label=None):
        super().__init__(patches, label)
        self.patches = list(patches)
        self.errorbar = errorbar
        self.datavalues = datavalues
        self.orientation = orientation


class ErrorbarContainer(Container):
    def __init__(self, lines, has_xerr=False, has_yerr=False, *, label=None):
        super().__init__(lines, label)
        self.lines = lines
        self.has_xerr = has_xerr
        self.has_yerr = has_yerr


class StemContainer(Container):
    def __init__(self, markerline_stemlines_baseline, *, label=None):
        super().__init__(markerline_stemlines_baseline, label)
        self.markerline = markerline_stemlines_baseline[0] if markerline_stemlines_baseline else None
        self.stemlines = markerline_stemlines_baseline[1] if len(markerline_stemlines_baseline) > 1 else None
        self.baseline = markerline_stemlines_baseline[2] if len(markerline_stemlines_baseline) > 2 else None
